'use strict';

const chunkWorkers=[];let workerCursor=0;const pendingWorkerMeshes=new Map();
function applyEditsToChunk(cx,cz,chunk){let changed=false;for(const [key,blockId] of game.modifiedBlocksByChunk.get(chunkKey(cx,cz))||[]){const [x,y,z]=key.split(',').map(Number);chunk[blockIndex(x&15,y,z&15)]=blockId;changed=true;}return changed;}
function uploadWorkerMesh(cx,cz,opaque,water){const key=chunkKey(cx,cz),old=game.chunkMeshes.get(key);if(old){for(const vao of [old.vao,old.waterVao])if(vao)game.gl.deleteVertexArray(vao);for(const buffer of [old.vbo,old.waterVbo])if(buffer)game.gl.deleteBuffer(buffer);}const mesh={cx,cz,centerX:cx*16+8,centerZ:cz*16+8,vao:null,vbo:null,vertCount:0,waterVao:null,waterVbo:null,waterVertCount:0},bind=(loc,size,stride,offset)=>{if(loc<0)return;game.gl.enableVertexAttribArray(loc);game.gl.vertexAttribPointer(loc,size,game.gl.FLOAT,false,stride,offset);};if(opaque?.length){mesh.vao=game.gl.createVertexArray();mesh.vbo=game.gl.createBuffer();game.gl.bindVertexArray(mesh.vao);game.gl.bindBuffer(game.gl.ARRAY_BUFFER,mesh.vbo);game.gl.bufferData(game.gl.ARRAY_BUFFER,opaque,game.gl.STATIC_DRAW);bind(tAPos,3,36,0);bind(tAUV,2,36,12);bind(tANorm,1,36,20);bind(tAAO,1,36,24);bind(tALight,2,36,28);mesh.vertCount=opaque.length/9;}if(water?.length){mesh.waterVao=game.gl.createVertexArray();mesh.waterVbo=game.gl.createBuffer();game.gl.bindVertexArray(mesh.waterVao);game.gl.bindBuffer(game.gl.ARRAY_BUFFER,mesh.waterVbo);game.gl.bufferData(game.gl.ARRAY_BUFFER,water,game.gl.STATIC_DRAW);bind(wAPos,3,40,0);bind(wAUV,2,40,12);bind(wANorm,1,40,20);bind(wAAO,1,40,24);bind(wALight,2,40,28);bind(wAMaterial,1,40,36);mesh.waterVertCount=water.length/10;}game.gl.bindVertexArray(null);game.chunkMeshes.set(key,mesh);}
function installStreamedChunk(cx,cz,chunk){const key=chunkKey(cx,cz);game.chunkStreaming.pending.delete(key);if(game.chunks.has(key))return false;game.chunks.set(key,chunk);applyEditsToChunk(cx,cz,chunk);for(let z=cz*16;z<cz*16+16;z++)for(let x=cx*16;x<cx*16+16;x++)updateSkyHeightColumn(x,z);return true;}
function initializeChunkWorkers(){if(chunkWorkers.length||typeof Worker==='undefined')return;const onmessage=event=>{if(event.data.type==='mesh'){const key=chunkKey(event.data.cx,event.data.cz),requestedRevision=pendingWorkerMeshes.get(key);pendingWorkerMeshes.delete(key);if(game.chunks.has(key)&&requestedRevision===event.data.revision&&event.data.revision===(game.chunkRevisions.get(key)||0))uploadWorkerMesh(event.data.cx,event.data.cz,event.data.opaque,event.data.water);}else installStreamedChunk(event.data.cx,event.data.cz,event.data.data);};for(let i=0;i<2;i++){const worker=new Worker('js/chunk-worker.js?v=85');worker.onmessage=onmessage;worker.onerror=()=>{worker.terminate();const index=chunkWorkers.indexOf(worker);if(index>=0)chunkWorkers.splice(index,1);game.chunkStreaming.pending.clear();pendingWorkerMeshes.clear();};chunkWorkers.push(worker);}}
function nextChunkWorker(){initializeChunkWorkers();if(!chunkWorkers.length)return null;const worker=chunkWorkers[workerCursor%chunkWorkers.length];workerCursor++;return worker;}
function requestStreamedChunk(cx,cz){const key=chunkKey(cx,cz);if(game.chunks.has(key)||game.chunkStreaming.pending.has(key)||cx<0||cz<0||cx>=WORLD_CX||cz>=WORLD_CZ)return false;const worker=nextChunkWorker();if(worker){game.chunkStreaming.pending.add(key);worker.postMessage({type:'terrain',cx,cz,seed:game.worldSeed,version:game.generatorVersion});return true;}return installStreamedChunk(cx,cz,generateChunk(cx,cz));}
function requestWorkerMesh(cx,cz){const key=chunkKey(cx,cz),chunk=game.chunks.get(key);if(!chunk||game.chunkMeshes.has(key)||pendingWorkerMeshes.has(key))return;const worker=nextChunkWorker();if(!worker){game.dirtyChunks.add(key);return;}const revision=game.chunkRevisions.get(key)||0;pendingWorkerMeshes.set(key,revision);const copy=chunk.slice();worker.postMessage({type:'mesh',cx,cz,seed:game.worldSeed,version:game.generatorVersion,revision,data:copy},[copy.buffer]);}
function disposeChunk(key){const mesh=game.chunkMeshes.get(key);if(mesh){for(const vao of [mesh.vao,mesh.waterVao])if(vao)game.gl.deleteVertexArray(vao);for(const buffer of [mesh.vbo,mesh.waterVbo])if(buffer)game.gl.deleteBuffer(buffer);game.chunkMeshes.delete(key);}pendingWorkerMeshes.delete(key);game.chunks.delete(key);game.dirtyChunks.delete(key);}
function updateChunkStreaming(){if(game.generatorVersion<2||!game.worldLoaded)return;const stream=game.chunkStreaming,cx=Math.floor(game.player.x/16),cz=Math.floor(game.player.z/16);stream.lastCenterX=cx;stream.lastCenterZ=cz;const missing=CandyCore.planChunkRing(cx,cz,stream.prefetchRadius,WORLD_CX,WORLD_CZ,game.player.vx,game.player.vz).filter(pos=>!game.chunks.has(chunkKey(pos.cx,pos.cz))&&!stream.pending.has(chunkKey(pos.cx,pos.cz))),requestBudget=Math.max(0,4-stream.pending.size);for(let i=0;i<Math.min(requestBudget,missing.length);i++)requestStreamedChunk(missing[i].cx,missing[i].cz);let meshBudget=Math.max(0,2-pendingWorkerMeshes.size);for(const pos of CandyCore.planChunkRing(cx,cz,stream.activeRadius,WORLD_CX,WORLD_CZ,game.player.vx,game.player.vz)){if(meshBudget<=0)break;const key=chunkKey(pos.cx,pos.cz);if(game.chunks.has(key)&&!game.chunkMeshes.has(key)&&!pendingWorkerMeshes.has(key)){requestWorkerMesh(pos.cx,pos.cz);meshBudget--;}}if(game.chunks.size>stream.maxLoaded){const candidates=[];for(const key of game.chunks.keys()){const kx=Math.floor(key/WORLD_CZ),kz=key%WORLD_CZ,dist=Math.max(Math.abs(kx-cx),Math.abs(kz-cz));if(dist>stream.prefetchRadius)candidates.push({key,dist});}candidates.sort((a,b)=>b.dist-a.dist);for(const entry of candidates.slice(0,game.chunks.size-stream.maxLoaded))disposeChunk(entry.key);}if(document.documentElement.dataset.travelAudit==='returned'&&game.auditTravel){const marker=game.auditTravel.marker,key=chunkKey(marker.x>>4,marker.z>>4);if(game.chunks.has(key)){const restored=getBlock(marker.x,marker.y,marker.z)===FROSTING_PINK;document.documentElement.dataset.travelAudit=restored?'restored':'failed';document.getElementById('audit-status').textContent=restored?'Marker edit restored after return.':'Marker restoration failed.';}}document.documentElement.dataset.chunkStats=[game.chunks.size,game.chunkMeshes.size,stream.pending.size,pendingWorkerMeshes.size,WORLD_W,cx,cz].join(',');}
